mapper.select:
/* btchMgmtMapper.getCmnJuiceBtchLogList */
SELECT CJBM.OPRT_SCTN_CD , CMN.CD_DSC , CJBM.OPRT_STAT_CD , (SELECT B.CD_DSC FROM CMN_GRP_MST A, CMN_GRP_CD_MST B WHERE A.GRP_ID = B.GRP_ID AND A.GRP_ID = 'CMN0110' AND A.USG_YN = 'Y' AND B.USG_YN = 'Y' AND B.CD_VAL = CJBM.OPRT_STAT_CD) AS OPRT_STAT_NM , TO_CHAR(CJBM.OPRT_STRT_DT, 'YYYY-MM-DD HH24:MI:SS') AS OPRT_STRT_DT , TO_CHAR(CJBM.OPRT_END_DT, 'YYYY-MM-DD HH24:MI:SS') AS OPRT_END_DT , CJBM.REMRK , CJBM.OPRT_SUCC_DATA_CNT , B.OPRT_FILE_NM , B.OPRT_SUCC_DATA_CNT DTL_CNT FROM CMN_JUICE_BATCH_MST CJBM , (SELECT CJBD.OPRT_DT , CJBD.OPRT_SCTN_CD , CJBD.OPRT_SEQ , CJBD.OPRT_FILE_NM , OPRT_SUCC_DATA_CNT FROM CMN_JUICE_BATCH_DTL CJBD WHERE CJBD.OPRT_MOD = 'S') B , (SELECT CGCM.CD_VAL , CGCM.CD_DSC , CGCM.ETC1 FROM CMN_GRP_MST CGM , CMN_GRP_CD_MST CGCM WHERE CGM.GRP_ID = CGCM.GRP_ID AND CGM.GRP_ID = 'CMN0109' AND CGM.USG_YN = 'Y' AND CGCM.USG_YN = 'Y') CMN WHERE 1=1 AND CJBM.OPRT_DT = B.OPRT_DT(+) AND CJBM.OPRT_SCTN_CD = B.OPRT_SCTN_CD(+) AND CJBM.OPRT_SEQ = B.OPRT_SEQ(+) AND CJBM.OPRT_SCTN_CD = CMN.CD_VAL
AND CJBM.OPRT_SCTN_CD = #{oprtSctnCd, jdbcType=VARCHAR}
AND CJBM.OPRT_DT BETWEEN #{oprtStrtDt, jdbcType=VARCHAR} AND #{oprtEndDt, jdbcType=VARCHAR}
AND CJBM.OPRT_STAT_CD = #{oprtStatCd, jdbcType=VARCHAR}
AND CJBM.OPRT_SUCC_DATA_CNT > 0
ORDER BY OPRT_STRT_DT DESC

/* btchMgmtMapper.getBatchInfo */ SELECT BATCH_JOB_ID ,BATCH_JOB_NM ,BATCH_JOB_DSC ,DUTY_SCTN ,FN_GET_CODENM('CMN0023', DUTY_SCTN) AS DUTY_SCTN_NM ,EXEC_SERVICE ,BATCH_TYPE_CD ,FN_GET_CODENM('CMN0024', BATCH_TYPE_CD) AS BATCH_TYPE_NM ,EXEC_TM_CD ,EXEC_CRON ,USG_YN ,FN_GET_CODENM('CMN0011', USG_YN) AS USG_YN_NM ,SERVER_TYPE ,FN_GET_CODENM('CMN0029', SERVER_TYPE) AS SERVER_TYPE_NM FROM CMN_BATCH_INFO
AND BATCH_JOB_NM like '%' || #{searchBatchJobNm} || '%'
AND DUTY_SCTN = #{searchDutySctn}
AND USG_YN = #{searchUsgYn}
AND BATCH_TYPE_CD = #{searchBatchTypeCd}
AND SERVER_TYPE = #{serverType}
ORDER BY BATCH_JOB_ID

mapper.insert:

			SELECT 'BATCH' || LPAD(NVL(TO_NUMBER(SUBSTR(MAX(BATCH_JOB_ID), 6)),0) + 1, 5, '0') AS batchJobId
			FROM   CMN_BATCH_INFO

		/* btchMgmtMapper.insertBatchInfo */
		INSERT INTO CMN_BATCH_INFO
