			,#{execTmCd}
			,#{execCron}
			,#{usgYn}
			,#{sessionUserId}
			,SYSDATE
			,#{sessionUserId}
			,SYSDATE
			,#{serverType}
		)

mapper.select:
SELECT DECODE(COUNT(*) , 0 , 'N', 'Y') AS dupFlag
FROM   CMN_BATCH_INFO
WHERE  EXEC_SERVICE = #{execService}

mapper.update:
/* btchMgmtMapper.updateBatchInfo */
UPDATE CMN_BATCH_INFO
SET    BATCH_JOB_NM = #{batchJobNm}
      ,BATCH_JOB_DSC = #{batchJobDsc}
      ,DUTY_SCTN = #{dutySctn}
      ,EXEC_SERVICE = #{execService}
      ,BATCH_TYPE_CD = #{batchTypeCd}
      ,EXEC_TM_CD = #{execTmCd}
      ,EXEC_CRON = #{execCron}
      ,USG_YN = #{usgYn}
      ,RVISN_ID = #{sessionUserId}
      ,RVISN_DTTM = SYSDATE
      ,SERVER_TYPE = #{serverType}
WHERE  BATCH_JOB_ID = #{batchJobId}

mapper.select:
/* btchMgmtMapper.getBatchExecHst */ SELECT A.BATCH_JOB_ID ,A.BATCH_JOB_NM ,T.BATCH_EXEC_ID ,T.BATCH_REQ_ID ,T.STAT_CD ,FN_GET_CODENM('CMN0027', T.STAT_CD) AS STAT_NM ,T.STRT_DTTM ,T.END_DTTM ,T.EXEC_PARAM ,T.EXEC_COUNT ,T.ERR_CD ,T.ERR_MSG ,T.REMRK ,A.DUTY_SCTN ,FN_GET_CODENM('CMN0023', A.DUTY_SCTN) AS DUTY_SCTN_NM ,A.EXEC_SERVICE ,A.BATCH_TYPE_CD ,FN_GET_CODENM('CMN0024', A.BATCH_TYPE_CD) AS BATCH_TYPE_NM ,A.EXEC_CRON ,T.REQ_DTTM ,T.EXEC_TYPE_CD ,FN_GET_CODENM('CMN0028', T.EXEC_TYPE_CD) AS EXEC_TYPE_NM ,A.SERVER_TYPE ,FN_GET_CODENM('CMN0029', A.SERVER_TYPE) AS SERVER_TYPE_NM FROM CMN_BATCH_INFO A ,(SELECT NVL(B.BATCH_JOB_ID, C.BATCH_JOB_ID) AS BATCH_JOB_ID ,B.BATCH_EXEC_ID ,C.BATCH_REQ_ID ,NVL(B.STAT_CD, 'STB') AS STAT_CD ,B.STRT_DTTM ,B.END_DTTM ,NVL(B.EXEC_PARAM, C.EXEC_PARAM) AS EXEC_PARAM ,B.EXEC_COUNT ,B.ERR_CD ,B.ERR_MSG ,B.REMRK ,C.REQ_DTTM ,NVL(B.EXEC_TYPE_CD, C.EXEC_TYPE_CD) AS EXEC_TYPE_CD FROM CMN_BATCH_EXEC_HST B FULL OUTER JOIN CMN_BATCH_REQUEST C ON B.BATCH_JOB_ID = C.BATCH_JOB_ID AND B.BATCH_REQ_ID = C.BATCH_REQ_ID WHERE (B.STRT_DTTM BETWEEN #{searchStartDate} || '000000' AND #{searchEndDate} || '235959' OR C.REQ_DTTM BETWEEN #{searchStartDate} || '000000' AND #{searchEndDate} || '235959') ) T WHERE A.BATCH_JOB_ID = T.BATCH_JOB_ID
AND A.BATCH_JOB_ID LIKE '%' || #{searchBatchJobId} || '%'
AND A.BATCH_JOB_NM LIKE '%' || #{searchBatchJobNm} || '%'
AND T.STAT_CD = #{searchStatCd}
AND A.DUTY_SCTN = #{searchDutySctn}
AND A.EXEC_SERVICE LIKE '%' || #{searchExecService} || '%'
AND SERVER_TYPE = #{serverType}
ORDER BY NVL(T.STRT_DTTM, T.REQ_DTTM) DESC
